  ('optician-moex-02238', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關隱形眼鏡清潔護理所使用的雙氧水消毒法之敘述，下列何者錯誤？', '["一步驟雙氧水消毒法需要定期更換白金環", "二步驟雙氧水消毒法需要需加入中和錠完全中和後才能配戴", "雙氧水消毒法對棘狀阿米巴原蟲殺菌、消毒效果比多功能護理液佳", "雙氧水消毒法可能會改變高含水鏡片的參數，此為不可逆的反應"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "823ea7ba277e", "answer_pdf_sha1": "20080966bf93", "source_family": "moex-gov-tw", "moex": {"exam_code": "107110", "c": "113", "s": "1108", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、107年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
